<template><BaseModal :model-value="modelValue" @update:modelValue="$emit('update:modelValue',$event)" title="Check Out"><form class="space-y-3" @submit.prevent="submit"><input type="date" v-model="form.date" class="input" required><TimeChipSelector v-model="form.time"/><select class="input" v-model="form.unit_id"><option v-for="r in rooms" :value="r.value" :key="r.value">{{ r.label }}</option></select><textarea class="input h-24" v-model="form.note" placeholder="Notes"></textarea><input type="number" class="input" v-model.number="form.final_charges" placeholder="Final Charges"><button class="bg-red-500 text-white rounded-lg py-2 w-full">Check Out</button></form></BaseModal></template>
<script setup>import {reactive,watch} from 'vue'; import BaseModal from './BaseModal.vue'; import TimeChipSelector from './TimeChipSelector.vue'; const props=defineProps({modelValue:Boolean,rooms:Array,reservationId:Number,unitId:Number}); const emit=defineEmits(['update:modelValue','submitted']); const form=reactive({reservation_id:null,unit_id:null,date:new Date().toISOString().slice(0,10),time:'01:00 PM',note:'',final_charges:0}); watch(()=>[props.reservationId,props.unitId],()=>{form.reservation_id=props.reservationId; form.unit_id=props.unitId;},{immediate:true}); const submit=()=>emit('submitted',{...form});</script>
